public class Rectangle {
    private double width;
    private double height;

    public Rectangle(double width, double height) {
        this.width = width;
        this.height = height;
    }

    public double getArea() {
        return width * height;
    }

    public double getPerimeter() {
        return 2 * (width + height);
    }

    public boolean isSquare() {
        return width == height;
    }

    public String toString() {
        return "Rectangle(" + width + " x " + height + ")";
    }

    public static void main(String[] args) {
        Rectangle r1 = new Rectangle(5.0, 3.0);
        Rectangle r2 = new Rectangle(4.0, 4.0);
        System.out.println(r1 + " Area: " + r1.getArea() + " Perimeter: " + r1.getPerimeter() + " Square? " + r1.isSquare());
        System.out.println(r2 + " Area: " + r2.getArea() + " Perimeter: " + r2.getPerimeter() + " Square? " + r2.isSquare());
    }
}

