public class Pet {
    private String name;
    private String species;
    private int age;
    private int hunger;

    public Pet(String name, String species, int age) {
        this.name = name;
        this.species = species;
        this.age = age;
        this.hunger = 5;
    }

    public void feed() {
        hunger = Math.max(0, hunger - 3);
    }

    public void play() {
        hunger = Math.min(10, hunger + 2);
    }

    public String getStatus() {
        if (hunger < 4) return "happy";
        if (hunger <= 7) return "okay";
        return "hungry";
    }

    public String toString() {
        return name + " the " + species + " (age " + age + ") - " + getStatus();
    }

    public static void main(String[] args) {
        Pet p = new Pet("Buddy", "Dog", 3);
        System.out.println(p);
        p.feed();
        System.out.println(p);
        p.play();
        p.play();
        p.play();
        System.out.println(p);
    }
}

