public class GameCharacter {
    private String name;
    private int health;
    private int attackPower;

    public GameCharacter(String name, int attackPower) {
        this.name = name;
        this.health = 100;
        this.attackPower = attackPower;
    }

    public void attack(GameCharacter other) {
        other.takeDamage(this.attackPower);
    }

    public void takeDamage(int damage) {
        health = Math.max(0, health - damage);
    }

    public void heal(int amount) {
        health = Math.min(100, health + amount);
    }

    public boolean isAlive() {
        return health > 0;
    }

    public String toString() {
        return name + " [HP: " + health + "/100] (ATK: " + attackPower + ")";
    }

    public static void main(String[] args) {
        GameCharacter hero = new GameCharacter("Hero", 25);
        GameCharacter villain = new GameCharacter("Villain", 30);
        System.out.println(hero);
        System.out.println(villain);
        hero.attack(villain);
        villain.attack(hero);
        System.out.println(hero);
        System.out.println(villain);
        hero.heal(10);
        System.out.println(hero);
    }
}
